import{_ as h,o as n,c as a,a0 as i}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Thiết lập Kế toán","description":"","frontmatter":{"title":"Thiết lập Kế toán"},"headers":[],"relativePath":"accounts-settings.md","filePath":"accounts-settings.md"}'),o={name:"accounts-settings.md"};function c(r,t,l,g,e,u){return n(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="thiet-lap-ke-toan" tabindex="-1">Thiết lập Kế toán <a class="header-anchor" href="#thiet-lap-ke-toan" aria-label="Permalink to &quot;Thiết lập Kế toán&quot;">​</a></h1><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Thiết lập Kế toán (Accounts Settings) là nơi bạn cấu hình các hành vi mặc định cho toàn bộ mô-đun Kế toán trong ABNERP. Việc cấu hình đúng đắn ngay từ đầu sẽ giúp hệ thống vận hành trơn tru và đảm bảo tính chính xác của số liệu tài chính.</p><h2 id="cach-truy-cap" tabindex="-1">Cách truy cập <a class="header-anchor" href="#cach-truy-cap" aria-label="Permalink to &quot;Cách truy cập&quot;">​</a></h2><p>Vào <strong>Kế toán &gt; Thiết lập &gt; Thiết lập Kế toán</strong>, hoặc tìm kiếm &quot;Thiết lập Kế toán&quot; từ thanh công cụ toàn cầu.</p><h2 id="cac-thiet-lap-chinh" tabindex="-1">Các thiết lập chính <a class="header-anchor" href="#cac-thiet-lap-chinh" aria-label="Permalink to &quot;Các thiết lập chính&quot;">​</a></h2><h3 id="thiet-lap-so-du-đau-ky" tabindex="-1">Thiết lập Số dư Đầu kỳ <a class="header-anchor" href="#thiet-lap-so-du-đau-ky" aria-label="Permalink to &quot;Thiết lập Số dư Đầu kỳ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Trường</th><th>Mô tả</th></tr></thead><tbody><tr><td>Cho phép nhập số dư đầu kỳ</td><td>Bật để cho phép nhập số dư ban đầu</td></tr><tr><td>Ngày bắt đầu</td><td>Ngày mở sổ kế toán trên hệ thống</td></tr><tr><td>Tài khoản lũy kế</td><td>Tài khoản đối ứng khi nhập số dư đầu kỳ</td></tr></tbody></table><p>Khi nhập số dư đầu kỳ, hệ thống tạo một bút toán tổng hợp để cân đối giữa tổng tài sản và tổng nguồn vốn.</p><h3 id="tu-đong-ghi-so" tabindex="-1">Tự động ghi sổ <a class="header-anchor" href="#tu-đong-ghi-so" aria-label="Permalink to &quot;Tự động ghi sổ&quot;">​</a></h3><p>Các thiết lập liên quan đến tự động hóa hạch toán:</p><ul><li><strong>Tự động ghi sổ bút toán</strong>: Khi được bật, bút toán sẽ được tự động ghi nhận (posted) ngay khi được tạo, thay vì ở trạng thái nháp (draft).</li><li><strong>Tự động ghi sổ hóa đơn bán hàng</strong>: Hóa đơn bán hàng sẽ tự động được ghi sổ và cập nhật công nợ sau khi lưu.</li><li><strong>Tự động ghi sổ hóa đơn mua hàng</strong>: Tương tự cho hóa đơn mua hàng.</li></ul><h3 id="thue-mac-đinh" tabindex="-1">Thuế mặc định <a class="header-anchor" href="#thue-mac-đinh" aria-label="Permalink to &quot;Thuế mặc định&quot;">​</a></h3><ul><li><strong>Thuế bán hàng mặc định</strong>: Loại thuế được áp dụng tự động khi tạo hóa đơn bán hàng.</li><li><strong>Thuế mua hàng mặc định</strong>: Loại thuế được áp dụng tự động khi tạo hóa đơn mua hàng.</li><li><strong>Tài khoản thuế đầu ra</strong>: Tài khoản mặc định để hạch toán thuế GTGT đầu ra.</li><li><strong>Tài khoản thuế đầu vào</strong>: Tài khoản mặc định để hạch toán thuế GTGT đầu vào.</li></ul><h3 id="cac-thiet-lap-khac" tabindex="-1">Các thiết lập khác <a class="header-anchor" href="#cac-thiet-lap-khac" aria-label="Permalink to &quot;Các thiết lập khác&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Thiết lập</th><th>Mô tả</th></tr></thead><tbody><tr><td>Tài khoản tồn kho mặc định</td><td>Tài khoản sử dụng cho hàng tồn kho</td></tr><tr><td>Tài khoản chi phí mặc định</td><td>Tài khoản sử dụng khi không chỉ định tài khoản chi phí cụ thể</td></tr><tr><td>Tài khoản doanh thu mặc định</td><td>Tài khoản sử dụng khi không chỉ định tài khoản doanh thu cụ thể</td></tr><tr><td>Làm tròn số</td><td>Làm tròn số tiền trên hóa đơn và bút toán</td></tr><tr><td>Số thập phân</td><td>Số chữ số thập phân cho các giao dịch kế toán</td></tr><tr><td>Mẫu báo cáo tài chính</td><td>Báo cáo tài chính mặc định cho công ty</td></tr></tbody></table><h3 id="thiet-lap-ve-cong-no" tabindex="-1">Thiết lập về công nợ <a class="header-anchor" href="#thiet-lap-ve-cong-no" aria-label="Permalink to &quot;Thiết lập về công nợ&quot;">​</a></h3><ul><li><strong>Tuổi nợ công nợ</strong>: Cấu hình các khoảng thời gian để phân tích tuổi nợ công nợ phải thu và phải trả.</li><li><strong>Giới hạn tín dụng</strong>: Cho phép thiết lập và kiểm tra hạn mức tín dụng cho từng khách hàng.</li><li><strong>Cảnh báo quá hạn</strong>: Bật/tắt cảnh báo khi hóa đơn đến hạn thanh toán.</li></ul><h3 id="thiet-lap-thanh-toan" tabindex="-1">Thiết lập thanh toán <a class="header-anchor" href="#thiet-lap-thanh-toan" aria-label="Permalink to &quot;Thiết lập thanh toán&quot;">​</a></h3><ul><li><strong>Phương thức thanh toán mặc định</strong>: Phương thức thanh toán được chọn tự động.</li><li><strong>Cho phép thanh toán một phần</strong>: Cho phép thanh toán từng phần trên một hóa đơn.</li><li><strong>Đối trừ tự động</strong>: Tự động gợi ý các hóa đơn cần đối trừ khi nhận thanh toán.</li></ul><h3 id="kiem-soat-truy-cap" tabindex="-1">Kiểm soát truy cập <a class="header-anchor" href="#kiem-soat-truy-cap" aria-label="Permalink to &quot;Kiểm soát truy cập&quot;">​</a></h3><ul><li><strong>Chỉ cho phép kế toán trưởng duyệt</strong>: Giới hạn quyền duyệt và ghi sổ cho người dùng có vai trò cụ thể.</li><li><strong>Yêu cầu mật khẩu khi duyệt</strong>: Tăng cường bảo mật khi thực hiện các thao tác quan trọng.</li></ul><h2 id="luu-y-quan-trong" tabindex="-1">Lưu ý quan trọng <a class="header-anchor" href="#luu-y-quan-trong" aria-label="Permalink to &quot;Lưu ý quan trọng&quot;">​</a></h2><ul><li>Một số thiết lập chỉ có hiệu lực với giao dịch mới, không ảnh hưởng đến giao dịch đã tạo</li><li>Thay đổi tài khoản mặc định có thể ảnh hưởng đến các báo cáo hiện tại</li><li>Nên kiểm tra và cấu hình đầy đủ trước khi đưa hệ thống vào vận hành chính thức</li><li>Tham khảo ý kiến chuyên gia kế toán để đảm bảo tuân thủ chế độ kế toán hiện hành</li></ul>',24)])])}const p=h(o,[["render",c]]);export{d as __pageData,p as default};
